//! Synthesise the scratch `Cargo.toml` that drives `cargo vendor`.
//!
//! `cargo vendor` takes a real Cargo workspace as input and walks its
//! dependency graph. We don't have a real workspace — we have a
//! `BuildModel::external_deps` arena. So we emit a minimal
//! single-package manifest that lists every CratesIo and Git dep as a
//! `[dependencies.<name>]` table. Cargo resolves the graph, writes a
//! `Cargo.lock`, and populates `vendor/` exactly as if it had been
//! asked to vendor a normal workspace.
//!
//! # What's in the generated package
//!
//! - `[package]`: a fixed-name, un-publishable stub so cargo has
//!   something to anchor its package metadata to.
//! - `[lib]`: points at a stub `lib.rs` co-located with the manifest.
//!   We materialise that file in [`write_vendor_workspace`] — without
//!   it, cargo refuses to parse the manifest.
//! - `[dependencies]`: one table per non-Path external dep. Path deps
//!   are excluded entirely — `cargo vendor` would leave them in place
//!   anyway, and including them would force the scratch workspace to
//!   point at a path that may not exist from the workspace's
//!   perspective.
//!
//! # Why hand-rolled TOML instead of `toml::to_string`
//!
//! Cargo is pickier than `toml`'s serde round-trip about certain
//! shapes (e.g. per-dep tables under `[dependencies.foo]` with a
//! mixture of string and boolean fields). Hand-rolling the output
//! lets us lay it out the way cargo documents and avoids the chance
//! of a future `toml` crate release emitting inline-table syntax that
//! cargo refuses to parse. The output is small (one stanza per dep)
//! so this is not a maintenance burden.

use crate::error::{Diagnostic, Error, Result};
use gluon_model::{Arena, DepSource, ExternalDepDef, GitRef};
use std::fmt::Write as _;
use std::fs;
use std::path::Path;

/// Fixed stub package name embedded in the generated manifest. Not
/// user-visible — cargo only needs *something* here to satisfy the
/// `[package]` table. Gluon never publishes this crate and cargo
/// vendor does not care about the name.
const WORKSPACE_PACKAGE_NAME: &str = "gluon-vendor-workspace";

/// Stub `lib.rs` contents. Cargo requires the target file to exist;
/// the contents are irrelevant because cargo vendor only reads
/// Cargo.toml + resolves deps, never builds the workspace.
const STUB_LIB_RS: &str = "// Auto-generated stub for `cargo vendor`. Do not edit.\n";

/// Render the scratch `Cargo.toml` for the given external deps.
///
/// Returns the full manifest as a `String`. Path-sourced deps are
/// silently skipped — see the module docs.
///
/// # Errors
///
/// Returns an [`Error::Diagnostics`] with the dep's `span` attached
/// when a [`DepSource::CratesIo`] entry has an empty version (the
/// Rhai builder defaults to `""` when `.version()` is never called,
/// which is a user error we detect here rather than at `cargo vendor`
/// time so the diagnostic points at the right line in `gluon.rhai`).
pub fn generate_vendor_cargo_toml(deps: &Arena<ExternalDepDef>) -> Result<String> {
    // Collect diagnostics across all deps so the user sees every
    // problem in one pass, not just the first one. Matches the
    // accumulate-then-report pattern used by the intern pass.
    let mut diags: Vec<Diagnostic> = Vec::new();

    let mut out = String::new();
    out.push_str("# Auto-generated by `gluon vendor`. Do not edit by hand.\n\n");
    out.push_str("[package]\n");
    writeln!(out, "name = \"{}\"", WORKSPACE_PACKAGE_NAME).unwrap();
    out.push_str("version = \"0.0.0\"\n");
    out.push_str("edition = \"2021\"\n");
    out.push_str("publish = false\n\n");
    out.push_str("[lib]\n");
    out.push_str("path = \"lib.rs\"\n\n");

    // Deterministic iteration: `Arena::names()` walks a BTreeMap so
    // this is already sorted, but make it explicit for safety.
    let mut entries: Vec<(&str, &ExternalDepDef)> = deps
        .names()
        .filter_map(|(name, h)| deps.get(h).map(|d| (name, d)))
        .collect();
    entries.sort_by_key(|(name, _)| *name);

    for (name, dep) in entries {
        // Skip path deps — see module docs.
        if matches!(dep.source, DepSource::Path { .. }) {
            continue;
        }

        writeln!(out, "[dependencies.{}]", name).unwrap();

        match &dep.source {
            DepSource::CratesIo { version } => {
                if version.is_empty() {
                    diags.push(
                        Diagnostic::error(format!(
                            "dependency \"{name}\" has no version specified"
                        ))
                        .with_optional_span(dep.span.clone())
                        .with_note("call `.version(\"x.y\")` on the dependency builder"),
                    );
                    // Still emit a placeholder so further deps parse
                    // in isolation if the user fixes this one.
                    out.push_str("version = \"0.0.0\"\n");
                } else {
                    writeln!(out, "version = \"{}\"", escape_toml_str(version)).unwrap();
                }
            }
            DepSource::Git { url, reference } => {
                writeln!(out, "git = \"{}\"", escape_toml_str(url)).unwrap();
                match reference {
                    GitRef::Rev(s) => {
                        writeln!(out, "rev = \"{}\"", escape_toml_str(s)).unwrap();
                    }
                    GitRef::Tag(s) => {
                        writeln!(out, "tag = \"{}\"", escape_toml_str(s)).unwrap();
                    }
                    GitRef::Branch(s) => {
                        writeln!(out, "branch = \"{}\"", escape_toml_str(s)).unwrap();
                    }
                    GitRef::Default => {
                        // No ref key; cargo follows the default branch.
                    }
                }
            }
            DepSource::Path { .. } => unreachable!("filtered above"),
        }

        // `default-features` — only emit when false, matching cargo's
        // convention (the default is `true`). Emitting it always is
        // legal but noisy.
        if !dep.default_features {
            out.push_str("default-features = false\n");
        }

        if !dep.features.is_empty() {
            // Sort for determinism — same reason as in the
            // fingerprint.
            let mut sorted: Vec<&String> = dep.features.iter().collect();
            sorted.sort();
            out.push_str("features = [");
            for (i, f) in sorted.iter().enumerate() {
                if i > 0 {
                    out.push_str(", ");
                }
                write!(out, "\"{}\"", escape_toml_str(f)).unwrap();
            }
            out.push_str("]\n");
        }

        out.push('\n');
    }

    if !diags.is_empty() {
        return Err(Error::Diagnostics(diags));
    }
    Ok(out)
}

/// Write the generated manifest and stub `lib.rs` into
/// `workspace_dir`, creating the directory if needed.
///
/// The stub is rewritten on every call — it's three bytes and
/// deterministic, so there is no point being clever about caching.
/// The `Cargo.toml` is rewritten on every call for the same reason:
/// the caller is expected to have already decided that re-vendoring
/// is necessary.
pub fn write_vendor_workspace(workspace_dir: &Path, deps: &Arena<ExternalDepDef>) -> Result<()> {
    fs::create_dir_all(workspace_dir).map_err(|e| Error::Io {
        path: workspace_dir.to_path_buf(),
        source: e,
    })?;

    let manifest = generate_vendor_cargo_toml(deps)?;
    let manifest_path = workspace_dir.join("Cargo.toml");
    fs::write(&manifest_path, manifest.as_bytes()).map_err(|e| Error::Io {
        path: manifest_path,
        source: e,
    })?;

    let lib_path = workspace_dir.join("lib.rs");
    fs::write(&lib_path, STUB_LIB_RS.as_bytes()).map_err(|e| Error::Io {
        path: lib_path,
        source: e,
    })?;

    Ok(())
}

/// Escape a bare `"` inside a TOML basic string. The values we emit
/// (crate names, versions, URLs, feature names) shouldn't legitimately
/// contain a double-quote, but an unescaped one would produce broken
/// TOML so we handle it defensively. Backslashes are also escaped to
/// preserve round-trip fidelity for Windows paths.
fn escape_toml_str(s: &str) -> String {
    s.replace('\\', "\\\\").replace('"', "\\\"")
}

#[cfg(test)]
mod tests {
    use super::*;
    use gluon_model::SourceSpan;

    fn dep(name: &str, source: DepSource) -> ExternalDepDef {
        ExternalDepDef {
            name: name.into(),
            source,
            features: Vec::new(),
            default_features: true,
            cfg_flags: Vec::new(),
            rustc_flags: Vec::new(),
            span: None,
        }
    }

    fn arena(entries: Vec<ExternalDepDef>) -> Arena<ExternalDepDef> {
        let mut a = Arena::new();
        for e in entries {
            let name = e.name.clone();
            a.insert(name, e);
        }
        a
    }

    fn assert_parses_as_toml(s: &str) {
        let _: toml::Value = toml::from_str(s)
            .unwrap_or_else(|e| panic!("generated manifest is not valid TOML:\n{s}\n\nerror: {e}"));
    }

    #[test]
    fn empty_arena_emits_valid_package_only_manifest() {
        let out = generate_vendor_cargo_toml(&Arena::new()).expect("ok");
        assert_parses_as_toml(&out);
        assert!(out.contains("[package]"));
        assert!(out.contains(WORKSPACE_PACKAGE_NAME));
        assert!(out.contains("[lib]"));
        assert!(!out.contains("[dependencies."));
    }

    #[test]
    fn crates_io_dep_emits_version() {
        let out = generate_vendor_cargo_toml(&arena(vec![dep(
            "bitflags",
            DepSource::CratesIo {
                version: "2.11".into(),
            },
        )]))
        .expect("ok");
        assert_parses_as_toml(&out);
        assert!(out.contains("[dependencies.bitflags]"));
        assert!(out.contains("version = \"2.11\""));
    }

    #[test]
    fn empty_crates_io_version_is_diagnosed() {
        let mut d = dep("bitflags", DepSource::CratesIo { version: "".into() });
        d.span = Some(SourceSpan::point("gluon.rhai", 42, 1));
        let err = generate_vendor_cargo_toml(&arena(vec![d])).expect_err("must fail");
        let msg = err.to_string();
        assert!(msg.contains("no version specified"), "msg: {msg}");
        assert!(msg.contains("gluon.rhai:42:1"), "msg: {msg}");
        assert!(
            msg.contains(".version("),
            "should carry the fix hint, got: {msg}"
        );
    }

    #[test]
    fn git_rev_emits_rev_key() {
        let out = generate_vendor_cargo_toml(&arena(vec![dep(
            "tokio",
            DepSource::Git {
                url: "https://github.com/tokio-rs/tokio.git".into(),
                reference: GitRef::Rev("abc123def".into()),
            },
        )]))
        .expect("ok");
        assert_parses_as_toml(&out);
        assert!(out.contains("git = \"https://github.com/tokio-rs/tokio.git\""));
        assert!(out.contains("rev = \"abc123def\""));
        assert!(!out.contains("tag ="));
        assert!(!out.contains("branch ="));
    }

    #[test]
    fn git_tag_emits_tag_key() {
        let out = generate_vendor_cargo_toml(&arena(vec![dep(
            "x",
            DepSource::Git {
                url: "https://example.com/x.git".into(),
                reference: GitRef::Tag("v1.0".into()),
            },
        )]))
        .expect("ok");
        assert!(out.contains("tag = \"v1.0\""));
    }

    #[test]
    fn git_branch_emits_branch_key() {
        let out = generate_vendor_cargo_toml(&arena(vec![dep(
            "x",
            DepSource::Git {
                url: "https://example.com/x.git".into(),
                reference: GitRef::Branch("main".into()),
            },
        )]))
        .expect("ok");
        assert!(out.contains("branch = \"main\""));
    }

    #[test]
    fn git_default_ref_emits_no_ref_key() {
        let out = generate_vendor_cargo_toml(&arena(vec![dep(
            "x",
            DepSource::Git {
                url: "https://example.com/x.git".into(),
                reference: GitRef::Default,
            },
        )]))
        .expect("ok");
        assert!(!out.contains("rev ="));
        assert!(!out.contains("tag ="));
        assert!(!out.contains("branch ="));
        // But url is present.
        assert!(out.contains("git ="));
    }

    #[test]
    fn path_deps_are_omitted_entirely() {
        let out = generate_vendor_cargo_toml(&arena(vec![
            dep(
                "local-helper",
                DepSource::Path {
                    path: "../helper".into(),
                },
            ),
            dep(
                "log",
                DepSource::CratesIo {
                    version: "0.4".into(),
                },
            ),
        ]))
        .expect("ok");
        assert_parses_as_toml(&out);
        assert!(!out.contains("local-helper"), "path dep leaked: {out}");
        assert!(out.contains("[dependencies.log]"));
    }

    #[test]
    fn features_emitted_sorted_when_non_empty() {
        let mut d = dep(
            "x",
            DepSource::CratesIo {
                version: "1".into(),
            },
        );
        d.features = vec!["std".into(), "alloc".into(), "serde".into()];
        let out = generate_vendor_cargo_toml(&arena(vec![d])).expect("ok");
        assert_parses_as_toml(&out);
        // Sorted order: alloc, serde, std.
        assert!(
            out.contains("features = [\"alloc\", \"serde\", \"std\"]"),
            "out: {out}"
        );
    }

    #[test]
    fn default_features_only_emitted_when_false() {
        let mut d = dep(
            "x",
            DepSource::CratesIo {
                version: "1".into(),
            },
        );
        d.default_features = true;
        let out_true = generate_vendor_cargo_toml(&arena(vec![d.clone()])).expect("ok");
        assert!(!out_true.contains("default-features"));

        d.default_features = false;
        let out_false = generate_vendor_cargo_toml(&arena(vec![d])).expect("ok");
        assert!(out_false.contains("default-features = false"));
    }

    #[test]
    fn deps_emitted_in_sorted_order() {
        // Insertion order: z, a, m. Output must be: a, m, z.
        let out = generate_vendor_cargo_toml(&arena(vec![
            dep(
                "z",
                DepSource::CratesIo {
                    version: "1".into(),
                },
            ),
            dep(
                "a",
                DepSource::CratesIo {
                    version: "1".into(),
                },
            ),
            dep(
                "m",
                DepSource::CratesIo {
                    version: "1".into(),
                },
            ),
        ]))
        .expect("ok");
        let a = out.find("[dependencies.a]").expect("a");
        let m = out.find("[dependencies.m]").expect("m");
        let z = out.find("[dependencies.z]").expect("z");
        assert!(a < m && m < z, "order: a={a} m={m} z={z}\n{out}");
    }

    #[test]
    fn write_vendor_workspace_materialises_manifest_and_stub() {
        let tmp = tempfile::tempdir().expect("tempdir");
        let ws = tmp.path().join("vendor-workspace");
        write_vendor_workspace(
            &ws,
            &arena(vec![dep(
                "log",
                DepSource::CratesIo {
                    version: "0.4".into(),
                },
            )]),
        )
        .expect("ok");
        let manifest = std::fs::read_to_string(ws.join("Cargo.toml")).expect("read manifest");
        assert!(manifest.contains("[dependencies.log]"));
        let stub = std::fs::read_to_string(ws.join("lib.rs")).expect("read stub");
        assert!(stub.contains("Auto-generated stub"));
    }

    #[test]
    fn url_with_double_quote_is_escaped() {
        // A user could theoretically emit a url containing a quote via
        // a clever Rhai dynamic string. Don't let that produce broken
        // TOML.
        let out = generate_vendor_cargo_toml(&arena(vec![dep(
            "x",
            DepSource::Git {
                url: r#"https://example.com/"evil".git"#.into(),
                reference: GitRef::Default,
            },
        )]))
        .expect("ok");
        assert_parses_as_toml(&out);
    }
}
